package com.shecancode.user.controller; import com.shecancode.user.model.*; import com.shecancode.user.repo.*; import org.springframework.web.bind.annotation.*; import java.util.*; @RestController @RequestMapping("/api/users") public class UserController { private final UserRepository users;private final AddressRepository addresses;public UserController(UserRepository u,AddressRepository a){users=u;addresses=a;} @GetMapping public List<AppUser> all(){return users.findAll();} @GetMapping("/{id}") public AppUser one(@PathVariable Long id){return users.findById(id).orElseThrow();} @PutMapping("/{id}") public AppUser update(@PathVariable Long id,@RequestBody AppUser r){AppUser u=one(id);u.setFirstName(r.getFirstName());u.setLastName(r.getLastName());u.setEnabled(r.isEnabled());return users.save(u);} @PostMapping("/{userId}/addresses") public Address add(@PathVariable Long userId,@RequestBody Address a){one(userId);a.setUserId(userId);return addresses.save(a);} @GetMapping("/{userId}/addresses") public List<Address> list(@PathVariable Long userId){return addresses.findByUserId(userId);} @GetMapping("/{userId}/addresses/{id}") public Address address(@PathVariable Long userId,@PathVariable Long id){return addresses.findByIdAndUserId(id,userId).orElseThrow();} }